import{_ as r,o as d,c as n,a2 as s}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"修仙境界","description":"","frontmatter":{},"headers":[],"relativePath":"guide/jingjie.md","filePath":"guide/jingjie.md","lastUpdated":null}'),o={name:"guide/jingjie.md"};function a(l,t,i,e,g,h){return d(),n("div",null,[...t[0]||(t[0]=[s(`<h1 id="修仙境界" tabindex="-1">修仙境界 <a class="header-anchor" href="#修仙境界" aria-label="Permalink to &quot;修仙境界&quot;">​</a></h1><p>修仙之路共分 <strong>九大境界</strong>，从凡人到飞升仙界，每一步都需要积累修为、突破瓶颈。</p><h2 id="境界总览" tabindex="-1">境界总览 <a class="header-anchor" href="#境界总览" aria-label="Permalink to &quot;境界总览&quot;">​</a></h2><table tabindex="0"><thead><tr><th>境界</th><th>灵气基础</th><th>每小阶增幅</th><th>小阶成功率</th><th>大境界成功率</th><th>所需Boss</th><th>渡劫</th><th>天雷数</th><th>突破冷却</th></tr></thead><tbody><tr><td><strong>凡人</strong></td><td>—</td><td>—</td><td>—</td><td>—</td><td>—</td><td>❌</td><td>—</td><td>—</td></tr><tr><td><strong>练气</strong></td><td>200</td><td>+30/阶</td><td>75%</td><td>45%</td><td>—</td><td>❌</td><td>0</td><td>10秒</td></tr><tr><td><strong>筑基</strong></td><td>400</td><td>+60/阶</td><td>65%</td><td>40%</td><td>克苏鲁之眼</td><td>❌</td><td>0</td><td>15秒</td></tr><tr><td><strong>金丹</strong></td><td>800</td><td>+120/阶</td><td>55%</td><td>30%</td><td>骷髅王</td><td>✅</td><td>3道</td><td>20秒</td></tr><tr><td><strong>元婴</strong></td><td>1,600</td><td>+250/阶</td><td>45%</td><td>25%</td><td>双子魔眼</td><td>✅</td><td>6道</td><td>25秒</td></tr><tr><td><strong>化神</strong></td><td>3,200</td><td>+500/阶</td><td>38%</td><td>20%</td><td>世纪之花</td><td>✅</td><td>9道</td><td>30秒</td></tr><tr><td><strong>渡劫</strong></td><td>6,400</td><td>+1,000/阶</td><td>30%</td><td>15%</td><td>拜月教徒</td><td>✅</td><td>12道</td><td>40秒</td></tr><tr><td><strong>大乘</strong></td><td>12,800</td><td>+2,000/阶</td><td>25%</td><td>12%</td><td>月亮领主</td><td>✅</td><td>15道</td><td>50秒</td></tr><tr><td><strong>飞升</strong></td><td>25,600</td><td>+4,000/阶</td><td>18%</td><td>8%</td><td>月总加强</td><td>✅</td><td>18道</td><td>90秒</td></tr></tbody></table><hr><h2 id="各境界详解" tabindex="-1">各境界详解 <a class="header-anchor" href="#各境界详解" aria-label="Permalink to &quot;各境界详解&quot;">​</a></h2><h3 id="凡人" tabindex="-1">凡人 <a class="header-anchor" href="#凡人" aria-label="Permalink to &quot;凡人&quot;">​</a></h3><p>初次踏入修仙世界的起点，尚未觉醒修炼能力。需要先进行灵根觉醒。</p><h3 id="练气期" tabindex="-1">练气期 <a class="header-anchor" href="#练气期" aria-label="Permalink to &quot;练气期&quot;">​</a></h3><ul><li><strong>灵气基础值</strong>：200</li><li><strong>每小阶灵气增幅</strong>：30</li><li><strong>小阶突破成功率</strong>：75%</li><li><strong>大境界突破成功率</strong>：45%</li><li><strong>突破消耗比例</strong>：当前灵气的 70%</li><li><strong>所需修为</strong>：150</li><li><strong>属性加成</strong>：HP +5、防御 +1、速度 ×1.01、生命恢复 +1、魔力 +5</li></ul><blockquote><p>💡 练气期是修仙入门阶段，突破成功率较高，建议快速积累修为完成9个小阶。</p></blockquote><h3 id="筑基期" tabindex="-1">筑基期 <a class="header-anchor" href="#筑基期" aria-label="Permalink to &quot;筑基期&quot;">​</a></h3><ul><li><strong>灵气基础值</strong>：400</li><li><strong>每小阶灵气增幅</strong>：60</li><li><strong>小阶突破成功率</strong>：65%</li><li><strong>大境界突破成功率</strong>：40%</li><li><strong>突破消耗比例</strong>：当前灵气的 75%</li><li><strong>所需修为</strong>：300</li><li><strong>需击杀Boss</strong>：克苏鲁之眼</li><li><strong>属性加成</strong>：HP +5、防御 +2、速度 ×1.01、生命恢复 +1、魔力 +8</li></ul><h3 id="金丹期" tabindex="-1">金丹期 <a class="header-anchor" href="#金丹期" aria-label="Permalink to &quot;金丹期&quot;">​</a></h3><ul><li><strong>灵气基础值</strong>：800</li><li><strong>每小阶灵气增幅</strong>：120</li><li><strong>小阶突破成功率</strong>：55%</li><li><strong>大境界突破成功率</strong>：30%</li><li><strong>突破消耗比例</strong>：当前灵气的 80%</li><li><strong>所需修为</strong>：600</li><li><strong>需击杀Boss</strong>：骷髅王</li><li><strong>渡劫</strong>：3道天雷，每道 30 伤害</li><li><strong>属性加成</strong>：HP +5、防御 +3、速度 ×1.02、生命恢复 +2、魔力 +12</li></ul><blockquote><p>⚠️ 从金丹开始，突破大境界需要渡劫！记得备好<strong>渡劫丹</strong>和药水。</p></blockquote><h3 id="元婴期" tabindex="-1">元婴期 <a class="header-anchor" href="#元婴期" aria-label="Permalink to &quot;元婴期&quot;">​</a></h3><ul><li><strong>灵气基础值</strong>：1,600</li><li><strong>每小阶灵气增幅</strong>：250</li><li><strong>小阶突破成功率</strong>：45%</li><li><strong>大境界突破成功率</strong>：25%</li><li><strong>突破消耗比例</strong>：当前灵气的 82%</li><li><strong>所需修为</strong>：1,200</li><li><strong>需击杀Boss</strong>：双子魔眼</li><li><strong>渡劫</strong>：6道天雷，每道 60 伤害</li><li><strong>属性加成</strong>：HP +5、防御 +1、速度 ×1.02、生命恢复 +3、魔力 +16</li></ul><h3 id="化神期" tabindex="-1">化神期 <a class="header-anchor" href="#化神期" aria-label="Permalink to &quot;化神期&quot;">​</a></h3><ul><li><strong>灵气基础值</strong>：3,200</li><li><strong>每小阶灵气增幅</strong>：500</li><li><strong>小阶突破成功率</strong>：38%</li><li><strong>大境界突破成功率</strong>：20%</li><li><strong>突破消耗比例</strong>：当前灵气的 85%</li><li><strong>所需修为</strong>：2,500</li><li><strong>需击杀Boss</strong>：世纪之花</li><li><strong>渡劫</strong>：9道天雷，每道 100 伤害</li><li><strong>属性加成</strong>：HP +120、防御 +8、速度 ×1.03、生命恢复 +4、魔力 +20</li></ul><h3 id="渡劫期" tabindex="-1">渡劫期 <a class="header-anchor" href="#渡劫期" aria-label="Permalink to &quot;渡劫期&quot;">​</a></h3><ul><li><strong>灵气基础值</strong>：6,400</li><li><strong>每小阶灵气增幅</strong>：1,000</li><li><strong>小阶突破成功率</strong>：30%</li><li><strong>大境界突破成功率</strong>：15%</li><li><strong>突破消耗比例</strong>：当前灵气的 88%</li><li><strong>所需修为</strong>：5,000</li><li><strong>需击杀Boss</strong>：拜月教徒</li><li><strong>渡劫</strong>：12道天雷，每道 160 伤害</li><li><strong>属性加成</strong>：HP +5、防御 +2、速度 ×1.03、生命恢复 +5、魔力 +25</li></ul><blockquote><p>⚠️ 渡劫期突破成功率大幅下降，强烈建议准备<strong>高级或极品渡劫丹</strong>！</p></blockquote><h3 id="大乘期" tabindex="-1">大乘期 <a class="header-anchor" href="#大乘期" aria-label="Permalink to &quot;大乘期&quot;">​</a></h3><ul><li><strong>灵气基础值</strong>：12,800</li><li><strong>每小阶灵气增幅</strong>：2,000</li><li><strong>小阶突破成功率</strong>：25%</li><li><strong>大境界突破成功率</strong>：12%</li><li><strong>突破消耗比例</strong>：当前灵气的 90%</li><li><strong>所需修为</strong>：10,000</li><li><strong>需击杀Boss</strong>：月亮领主</li><li><strong>渡劫</strong>：15道天雷，每道 250 伤害（间隔 1.5 秒）</li><li><strong>属性加成</strong>：HP +250、防御 +18、速度 ×1.04、生命恢复 +7、魔力 +32</li></ul><h3 id="飞升期-最终境界" tabindex="-1">飞升期（最终境界） <a class="header-anchor" href="#飞升期-最终境界" aria-label="Permalink to &quot;飞升期（最终境界）&quot;">​</a></h3><ul><li><strong>灵气基础值</strong>：25,600</li><li><strong>每小阶灵气增幅</strong>：4,000</li><li><strong>小阶突破成功率</strong>：18%</li><li><strong>大境界突破成功率</strong>：8%</li><li><strong>突破消耗比例</strong>：当前灵气的 95%</li><li><strong>所需修为</strong>：20,000</li><li><strong>需击杀Boss</strong>：月总加强版</li><li><strong>渡劫</strong>：18道天雷，每道 400 伤害（间隔 1.5 秒）</li><li><strong>属性加成</strong>：HP +10、防御 +5、速度 ×1.05、生命恢复 +10、魔力 +40</li></ul><blockquote><p>🎉 达到飞升期即为服务器最高境界！享受最终属性加成和最强功法 <strong>飞升羽化</strong>！</p></blockquote><hr><h2 id="境界永久buff" tabindex="-1">境界永久Buff <a class="header-anchor" href="#境界永久buff" aria-label="Permalink to &quot;境界永久Buff&quot;">​</a></h2><p>每个境界提供不同的永久Buff加成：</p><table tabindex="0"><thead><tr><th>境界</th><th>Buff列表</th></tr></thead><tbody><tr><td>凡人</td><td>无</td></tr><tr><td>练气</td><td>1, 2, 9</td></tr><tr><td>筑基</td><td>1, 2, 3, 9, 5</td></tr><tr><td>金丹</td><td>2, 3, 6, 26, 5, 102</td></tr><tr><td>元婴</td><td>3, 11, 14, 15, 112, 83, 102</td></tr><tr><td>化神</td><td>3, 6, 26, 106, 113, 152, 83</td></tr><tr><td>渡劫</td><td>2, 3, 26, 113, 114, 152, 106</td></tr><tr><td>大乘</td><td>2, 3, 6, 26, 106, 113, 114, 57, 83</td></tr><tr><td>飞升</td><td>1, 2, 3, 6, 9, 11, 26, 106, 113, 114, 152, 57, 91</td></tr></tbody></table><hr><h2 id="突破机制详解" tabindex="-1">突破机制详解 <a class="header-anchor" href="#突破机制详解" aria-label="Permalink to &quot;突破机制详解&quot;">​</a></h2><h3 id="成功率计算公式" tabindex="-1">成功率计算公式 <a class="header-anchor" href="#成功率计算公式" aria-label="Permalink to &quot;成功率计算公式&quot;">​</a></h3><p>突破成功率由<strong>全局基础概率 × 境界配置概率</strong>叠加各项加成：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>小阶突破:</span></span>
<span class="line"><span>基础成功率 = 0.5（全局基础） × 境界小阶突破成功率</span></span>
<span class="line"><span></span></span>
<span class="line"><span>大境界突破:</span></span>
<span class="line"><span>基础成功率 = 0.25（全局基础） × 境界大境界突破成功率</span></span>
<span class="line"><span></span></span>
<span class="line"><span>最终成功率 = 基础成功率 + 灵根加成 + 突破丹加成 + 天道境界加成 + 事件加成</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><blockquote><p>📐 完整计算公式见 <a href="/guide/suanfa.html">算法公开</a>。</p></blockquote><h3 id="各境界实际成功率-仅基础部分-不含加成" tabindex="-1">各境界实际成功率（仅基础部分，不含加成） <a class="header-anchor" href="#各境界实际成功率-仅基础部分-不含加成" aria-label="Permalink to &quot;各境界实际成功率（仅基础部分，不含加成）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>境界</th><th>小阶基础</th><th>大境界基础</th></tr></thead><tbody><tr><td>练气</td><td>0.5 × 0.75 = <strong>37.5%</strong></td><td>0.25 × 0.45 = <strong>11.25%</strong></td></tr><tr><td>筑基</td><td>0.5 × 0.65 = <strong>32.5%</strong></td><td>0.25 × 0.40 = <strong>10.0%</strong></td></tr><tr><td>金丹</td><td>0.5 × 0.55 = <strong>27.5%</strong></td><td>0.25 × 0.30 = <strong>7.5%</strong></td></tr><tr><td>元婴</td><td>0.5 × 0.45 = <strong>22.5%</strong></td><td>0.25 × 0.25 = <strong>6.25%</strong></td></tr><tr><td>化神</td><td>0.5 × 0.38 = <strong>19.0%</strong></td><td>0.25 × 0.20 = <strong>5.0%</strong></td></tr><tr><td>渡劫</td><td>0.5 × 0.30 = <strong>15.0%</strong></td><td>0.25 × 0.15 = <strong>3.75%</strong></td></tr><tr><td>大乘</td><td>0.5 × 0.25 = <strong>12.5%</strong></td><td>0.25 × 0.12 = <strong>3.0%</strong></td></tr><tr><td>飞升</td><td>0.5 × 0.18 = <strong>9.0%</strong></td><td>0.25 × 0.08 = <strong>2.0%</strong></td></tr></tbody></table><h3 id="突破丹叠加" tabindex="-1">突破丹叠加 <a class="header-anchor" href="#突破丹叠加" aria-label="Permalink to &quot;突破丹叠加&quot;">​</a></h3><p>突破丹的基础加成为 <strong>+25%</strong>（全局配置 <code>突破丹加成: 0.25</code>），此为基础保底加成。</p><p>使用丹药可在此之上额外叠加：</p><table tabindex="0"><thead><tr><th>突破丹品质</th><th>额外加成</th><th>合计加成</th></tr></thead><tbody><tr><td>不使用</td><td>+0%</td><td>+25%</td></tr><tr><td>下阶</td><td>+20%</td><td>+45%</td></tr><tr><td>中等</td><td>+30%</td><td>+55%</td></tr><tr><td>高级</td><td>+45%</td><td>+70%</td></tr><tr><td>极品</td><td>+65%</td><td>+90%</td></tr></tbody></table><h3 id="小阶突破" tabindex="-1">小阶突破 <a class="header-anchor" href="#小阶突破" aria-label="Permalink to &quot;小阶突破&quot;">​</a></h3><ul><li>每个大境界包含 <strong>9个小阶</strong>（练气1阶 → 练气9阶）</li><li>消耗当前灵气的一定比例即可尝试突破</li><li>基础成功率随境界提升而递减</li><li>全局突破冷却：<strong>5秒</strong>（每次突破后等待）</li></ul><h3 id="大境界突破" tabindex="-1">大境界突破 <a class="header-anchor" href="#大境界突破" aria-label="Permalink to &quot;大境界突破&quot;">​</a></h3><ul><li>从练气9阶突破至筑基1阶，以此类推</li><li><strong>必须先击杀对应Boss</strong> 才能解锁大境界突破</li><li>金丹及以上境界需要 <strong>渡劫</strong>，承受天雷轰击</li><li>突破期间会被 <strong>定身</strong>（3秒），无法移动</li></ul><h3 id="连续失败保护" tabindex="-1">连续失败保护 <a class="header-anchor" href="#连续失败保护" aria-label="Permalink to &quot;连续失败保护&quot;">​</a></h3><ul><li>连续突破失败 <strong>3次</strong> 后自动触发保护机制</li><li>触发后获得 <strong>10功德</strong> 作为补偿</li><li>保护机制提高后续突破成功率</li></ul><h3 id="渡劫系统" tabindex="-1">渡劫系统 <a class="header-anchor" href="#渡劫系统" aria-label="Permalink to &quot;渡劫系统&quot;">​</a></h3><ul><li>金丹起每道天雷间隔 2.5 秒，大乘后缩短至 1.5 秒</li><li>渡劫失败扣血 <strong>150</strong></li><li>渡劫时会掉落物品</li><li><strong>天道境界</strong>越高，渡劫减伤越多（最高 <strong>40%</strong>）</li><li>渡劫丹可额外提升渡劫成功率</li></ul><h3 id="属性成长-全局配置" tabindex="-1">属性成长（全局配置） <a class="header-anchor" href="#属性成长-全局配置" aria-label="Permalink to &quot;属性成长（全局配置）&quot;">​</a></h3><p>每次小阶突破获得的属性加成（累加）：</p><table tabindex="0"><thead><tr><th>属性</th><th>每小阶加成</th></tr></thead><tbody><tr><td>HP上限</td><td>+10</td></tr><tr><td>防御</td><td>+1</td></tr><tr><td>魔力上限</td><td>+1</td></tr></tbody></table><p>每次大境界突破速度倍率 <strong>×1.02</strong>（累乘）：</p><ul><li>练气→飞升（8次大突破）：速度累计 ×1.02⁸ ≈ <strong>×1.172</strong></li></ul><hr><h2 id="死亡惩罚" tabindex="-1">死亡惩罚 <a class="header-anchor" href="#死亡惩罚" aria-label="Permalink to &quot;死亡惩罚&quot;">​</a></h2><ul><li>死亡扣除当前灵气的 <strong>25%</strong></li><li>需要保护好自己的灵气储备</li></ul><hr><h2 id="聊天显示" tabindex="-1">聊天显示 <a class="header-anchor" href="#聊天显示" aria-label="Permalink to &quot;聊天显示&quot;">​</a></h2><p>玩家聊天时自动显示当前境界前缀：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>格式: [{Realm}]{Name}: {Message}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>示例: <code>[金丹5阶]玩家名: 大家好！</code></p><blockquote><p>让所有玩家一眼看出彼此的修仙境界，高境界修士发言自带排面！</p></blockquote>`,66)])])}const p=r(o,[["render",a]]);export{b as __pageData,p as default};
